// This script will run when the page loads
// The mentorProfiles variable is already defined with 3 sample profiles
// We'll add more profiles to reach 30 total mentors

// Define regions for distribution
const regions = ['UK', 'US', 'Canada', 'Australia', 'Europe', 'Asia'];

// Define universities by region
const universities = {
  'UK': ['Oxford University', 'Cambridge University', 'Imperial College London', 'University College London', 'University of Edinburgh'],
  'US': ['Harvard University', 'Stanford University', 'MIT', 'Princeton University', 'Yale University'],
  'Canada': ['University of Toronto', 'McGill University', 'University of British Columbia', 'University of Waterloo', 'University of Alberta'],
  'Australia': ['University of Melbourne', 'University of Sydney', 'Australian National University', 'University of Queensland', 'Monash University'],
  'Europe': ['ETH Zurich', 'Sorbonne University', 'Technical University of Munich', 'University of Amsterdam', 'University of Copenhagen'],
  'Asia': ['National University of Singapore', 'Tsinghua University', 'University of Tokyo', 'Seoul National University', 'Peking University']
};

// Define degrees
const degrees = [
  'Computer Science', 'Mathematics', 'Physics', 'Engineering', 'Business Administration',
  'Economics', 'Medicine', 'Law', 'Psychology', 'Political Science', 'Literature',
  'History', 'Chemistry', 'Biology', 'Philosophy'
];

// Define specialties
const specialtiesList = [
  'Personal Statements', 'Interview Prep', 'University Selection', 'College Applications',
  'STEM Subjects', 'Programming', 'Medical School Applications', 'UCAT Prep',
  'Science Subjects', 'Essay Writing', 'Research Methods', 'Exam Techniques',
  'Study Skills', 'Time Management', 'Career Guidance', 'Portfolio Development',
  'Language Learning', 'Public Speaking', 'Data Analysis', 'Project Management'
];

// Define avatar URLs from Unsplash
const avatarUrls = [
  'https://images.unsplash.com/photo-1494790108377-be9c29b29330',
  'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d',
  'https://images.unsplash.com/photo-1438761681033-6461ffad8d80',
  'https://images.unsplash.com/photo-1500648767791-00dcc994a43e',
  'https://images.unsplash.com/photo-1534528741775-53994a69daeb',
  'https://images.unsplash.com/photo-1544005313-94ddf0286df2',
  'https://images.unsplash.com/photo-1517841905240-472988babdf9',
  'https://images.unsplash.com/photo-1539571696357-5a69c17a67c6',
  'https://images.unsplash.com/photo-1488161628813-04466f872be2',
  'https://images.unsplash.com/photo-1524250502761-1ac6f2e30d43',
  'https://images.unsplash.com/photo-1522075469751-3a6694fb2f61',
  'https://images.unsplash.com/photo-1531427186611-ecfd6d936c79',
  'https://images.unsplash.com/photo-1584999734482-0361aecad844',
  'https://images.unsplash.com/photo-1580489944761-15a19d654956',
  'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d'
];

// Get existing mentor profiles
let mentorProfiles = variables["52434ead-465a-4045-9fb8-d09f73debd6e"] || [];

// Generate additional mentor profiles to reach 30 total
const additionalProfiles = [];
const existingIds = new Set(mentorProfiles.map(mentor => mentor.id));

// Helper function to get random items from an array
const getRandomItems = (array, count) => {
  const shuffled = [...array].sort(() => 0.5 - Math.random());
  return shuffled.slice(0, count);
};

// Generate unique ID
const generateId = (existingIds) => {
  let id;
  do {
    id = Math.floor(Math.random() * 1000).toString();
  } while (existingIds.has(id));
  existingIds.add(id);
  return id;
};

// Generate additional profiles to reach 30 total
for (let i = mentorProfiles.length; i < 30; i++) {
  const region = regions[Math.floor(Math.random() * regions.length)];
  const university = universities[region][Math.floor(Math.random() * universities[region].length)];
  const degree = degrees[Math.floor(Math.random() * degrees.length)];
  const specialtiesCount = Math.floor(Math.random() * 3) + 1; // 1-3 specialties
  const specialties = getRandomItems(specialtiesList, specialtiesCount);
  const rating = (Math.random() * 1.5 + 3.5).toFixed(1); // Rating between 3.5 and 5.0
  const hourlyRate = Math.floor(Math.random() * 50) + 50; // Rate between 50 and 100
  const avatarUrl = avatarUrls[Math.floor(Math.random() * avatarUrls.length)];

  // Generate first and last name
  const firstNames = ['Emma', 'James', 'Olivia', 'Noah', 'Ava', 'William', 'Sophia', 'Benjamin', 'Isabella', 'Lucas', 'Mia', 'Henry', 'Charlotte', 'Alexander', 'Amelia'];
  const lastNames = ['Smith', 'Johnson', 'Williams', 'Brown', 'Jones', 'Miller', 'Davis', 'Garcia', 'Rodriguez', 'Wilson', 'Martinez', 'Anderson', 'Taylor', 'Thomas', 'Hernandez'];

  const firstName = firstNames[Math.floor(Math.random() * firstNames.length)];
  const lastName = lastNames[Math.floor(Math.random() * lastNames.length)];

  additionalProfiles.push({
    id: generateId(existingIds),
    name: `${firstName} ${lastName}`,
    avatar: avatarUrl,
    degree: degree,
    rating: parseFloat(rating),
    region: region,
    hourlyRate: hourlyRate,
    university: university,
    specialties: specialties,
    bio: `${university} ${degree} graduate specializing in ${specialties.join(', ')}. Passionate about helping students succeed in their academic journey.`
  });
}

// Combine existing and new profiles
variables["52434ead-465a-4045-9fb8-d09f73debd6e"] = [...mentorProfiles, ...additionalProfiles];

// Initialize selectedRegions if it doesn't exist
if (!variables['9c57fa47-0015-403a-a18c-620ce95936ff']) {
  variables['9c57fa47-0015-403a-a18c-620ce95936ff'] = [];
}

